import React, { useState } from "react";
import { useParams } from "react-router-dom";
import Navbar from "../components/Navbar";
import { createBooking } from "../services/api";

function Booking() {
  const { fieldId } = useParams();

  const [formData, setFormData] = useState({
    user_id: 1,
    field_id: Number(fieldId),
    booking_date: "",
    start_time: "",
    end_time: "",
    status: "pending",
  });

  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]:
        e.target.name === "user_id" || e.target.name === "field_id"
          ? Number(e.target.value)
          : e.target.value,
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    try {
      const result = await createBooking(formData);
      setMessage(`Đặt sân thành công! Mã booking: ${result.bookingId}`);
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div>
      <Navbar />

      <div className="container page-section">
        <div className="simple-card" style={{ maxWidth: "650px", margin: "0 auto" }}>
          <h1 className="section-title">Đặt sân bóng</h1>
          <p className="section-subtitle">
            Vui lòng điền đầy đủ thông tin để hoàn tất đặt sân.
          </p>

          <form className="booking-form" onSubmit={handleSubmit}>
            <div>
              <label>Mã người dùng</label>
              <input
                type="number"
                name="user_id"
                value={formData.user_id}
                onChange={handleChange}
              />
            </div>

            <div>
              <label>Mã sân</label>
              <input
                type="number"
                name="field_id"
                value={formData.field_id}
                onChange={handleChange}
                required
              />
            </div>

            <div>
              <label>Ngày đặt sân</label>
              <input
                type="date"
                name="booking_date"
                value={formData.booking_date}
                onChange={handleChange}
                required
              />
            </div>

            <div>
              <label>Giờ bắt đầu</label>
              <input
                type="time"
                name="start_time"
                value={formData.start_time}
                onChange={handleChange}
                required
              />
            </div>

            <div>
              <label>Giờ kết thúc</label>
              <input
                type="time"
                name="end_time"
                value={formData.end_time}
                onChange={handleChange}
                required
              />
            </div>

            <button type="submit" className="btn-primary" style={{ width: "fit-content" }}>
              Xác nhận đặt sân
            </button>
          </form>

          {message && <p className="success-text">{message}</p>}
          {error && <p className="error-text">{error}</p>}
        </div>
      </div>
    </div>
  );
}

export default Booking;
